@PostMapping("/login")
public Result<?> login(@RequestBody JSONObject params) {
    String username = params.getString("username");
    String password = params.getString("password");
    User user = userService.getByUsername(username);
    if (user == null) {
        return Result.error("用户名或密码错误");
    }
    String md5 = DigestUtils.md5DigestAsHex(
        password.getBytes(StandardCharsets.UTF_8));
    if (!md5.equals(user.getPassword())) {
        return Result.error("用户名或密码错误");
    }
    String token = JwtUtil.generateToken(user.getId(), user.getUserType());
    return Result.success(token);
}

@PostMapping("/register")
public Result<?> register(@RequestBody User user) {
    if (!IdCardUtil.isValid(user.getIdCard())) {
        return Result.error("身份证号格式不正确");
    }
    String md5 = DigestUtils.md5DigestAsHex(
        user.getPassword().getBytes(StandardCharsets.UTF_8));
    user.setPassword(md5);
    user.setBalance(BigDecimal.ZERO);
    user.setStatus(1);
    userService.save(user);
    return Result.success("注册成功");
}

@GetMapping("/list")
public Result<?> listMachines(
        @RequestParam(required = false) String area) {
    QueryWrapper<Machine> wrapper = new QueryWrapper<>();
    if (area != null) {
        wrapper.eq("area", area);
    }
    wrapper.orderByAsc("row_num", "col_num");
    return Result.success(machineService.list(wrapper));
}

@PostMapping("/create")
public Result<?> createReservation(
        @RequestAttribute("userId") Long userId,
        @RequestBody JSONObject params) {
    Long machineId = params.getLong("machineId");
    LocalDateTime startTime = LocalDateTime.parse(params.getString("startTime"));
    LocalDateTime endTime = LocalDateTime.parse(params.getString("endTime"));
    if (Duration.between(startTime, endTime).toMinutes() < 30) {
        return Result.error("预约时长最少30分钟");
    }
    if (reservationService.hasConflict(machineId, startTime, endTime)) {
        return Result.error("该时间段已被预约");
    }
    Reservation r = new Reservation();
    r.setUserId(userId);
    r.setMachineId(machineId);
    r.setStartTime(startTime);
    r.setEndTime(endTime);
    r.setStatus(0);
    reservationService.save(r);
    machineService.updateStatus(machineId, 2);
    return Result.success("预约成功");
}

@Transactional
public Session endSession(Long sessionId) {
    Session session = getById(sessionId);
    LocalDateTime endTime = LocalDateTime.now();
    long minutes = Duration.between(session.getStartTime(), endTime).toMinutes();
    Machine machine = machineService.getById(session.getMachineId());
    BigDecimal amount = calculateFee(
        machine.getMachineType(), session.getStartTime(), endTime);
    userService.deductBalance(session.getUserId(), amount);
    session.setEndTime(endTime);
    session.setDuration((int) minutes);
    session.setAmount(amount);
    session.setStatus(1);
    updateById(session);
    machineService.updateStatus(session.getMachineId(), 0);
    return session;
}

@PostMapping("/admin/login")
public Result<?> adminLogin(@RequestBody JSONObject params) {
    User user = userService.getByUsername(params.getString("username"));
    if (user == null || user.getUserType() != 1) {
        return Result.error("用户名或密码错误");
    }
    String md5 = DigestUtils.md5DigestAsHex(
        params.getString("password").getBytes(StandardCharsets.UTF_8));
    if (!md5.equals(user.getPassword())) {
        return Result.error("用户名或密码错误");
    }
    String token = JwtUtil.generateToken(user.getId(), user.getUserType());
    return Result.success(token);
}

@GetMapping("/dashboard/stats")
public Result<?> getDashboardStats() {
    JSONObject stats = new JSONObject();
    stats.put("todayRevenue",
        transactionService.sumAmountByDateAndType(LocalDate.now(), 2));
    stats.put("onlineCount",
        sessionService.count(new QueryWrapper<Session>().eq("status", 0)));
    stats.put("userCount", userService.count());
    stats.put("machineCount", machineService.count());
    return Result.success(stats);
}

@PostMapping("/machine")
public Result<?> addMachine(@RequestBody Machine machine) {
    machine.setStatus(0);
    machineService.save(machine);
    return Result.success("添加成功");
}

@DeleteMapping("/machine/{id}")
public Result<?> deleteMachine(@PathVariable Long id) {
    machineService.removeById(id);
    return Result.success("删除成功");
}

@PostMapping("/priceConfig")
public Result<?> addPriceConfig(@RequestBody PriceConfig config) {
    priceConfigService.save(config);
    return Result.success("添加成功");
}

@PutMapping("/priceConfig")
public Result<?> updatePriceConfig(@RequestBody PriceConfig config) {
    priceConfigService.updateById(config);
    return Result.success("修改成功");
}

@GetMapping("/reservation/page")
public Result<?> pageReservations(
        @RequestParam Integer pageNum, @RequestParam Integer pageSize,
        @RequestParam(required = false) Integer status) {
    QueryWrapper<Reservation> wrapper = new QueryWrapper<>();
    if (status != null) wrapper.eq("status", status);
    wrapper.orderByDesc("create_time");
    return Result.success(
        reservationService.page(new Page<>(pageNum, pageSize), wrapper));
}

@PutMapping("/user/status")
public Result<?> updateUserStatus(@RequestBody JSONObject params) {
    User user = userService.getById(params.getLong("id"));
    user.setStatus(params.getInteger("status"));
    userService.updateById(user);
    return Result.success("操作成功");
}
